import React from "react";

const services = [
  {
    id: 1,
    name: "Hotel Booking",
    description: "Book the best hotels at your favorite destinations.",
    image:
      "https://images.unsplash.com/photo-1568605114967-8130f3a36994?fit=crop&w=800&q=80",
  },
  {
    id: 2,
    name: "Makeup & Salon",
    description: "Professional hair styling and makeup for your travels.",
    image:
      "https://images.unsplash.com/photo-1508214751196-bcfd4ca60f91?fit=crop&w=800&q=80",
  },
  {
    id: 3,
    name: "Car Rentals",
    description: "Rent cars for your trips with flexible options.",
    image:
      "https://images.unsplash.com/photo-1533473359331-0135ef1b58bf?fit=crop&w=800&q=80",
  },
  {
    id: 4,
    name: "Tour Guides",
    description: "Explore destinations with expert local tour guides.",
    image:
      "https://images.unsplash.com/photo-1438761681033-6461ffad8d80?fit=crop&w=800&q=80",
  },
];

function Services() {
  return (
    <div className="min-h-screen bg-gradient-to-br from-yellow-50 via-pink-50 to-blue-50 py-12">
      {/* Title */}
      <h1 className="text-4xl sm:text-5xl font-extrabold text-center text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-pink-500 mb-12">
        Our Premium Services ✨
      </h1>

      {/* Service Cards */}
      <div className="flex flex-wrap justify-center gap-10 px-6">
        {services.map((service) => (
          <div
            key={service.id}
            className="bg-white rounded-2xl shadow-lg hover:shadow-2xl transform hover:-translate-y-2 transition-all duration-300 w-80 overflow-hidden"
          >
            <img
              src={service.image}
              alt={service.name}
              className="w-full h-52 object-cover hover:scale-105 transition-transform duration-500"
            />
            <div className="p-5 text-center">
              <h3 className="text-2xl font-semibold text-gray-800 mb-2">
                {service.name}
              </h3>
              <p className="text-gray-600 text-sm mb-4">{service.description}</p>
              <button className="bg-gradient-to-r from-pink-500 to-blue-600 text-white px-5 py-2 rounded-full shadow-md hover:shadow-lg transition-all duration-300">
                Learn More
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Services;
